// شعار وهيدر المستوصف (مضمّن كـ base64 ليعمل في الطباعة بدون اتصال إنترنت)
const String kHeaderLogoBase64 = 'data:image/jpeg;base64,';
// ═══════════════════════════════════════════
// نموذج سطر النتيجة الفرعي
// كل سطر ممكن يكون:
//  - سطر عنوان فقط (زي "Macroscopic Exam") → isHeader = true
//  - سطر نتيجة كامل: name + value + unit + normalRange
// ═══════════════════════════════════════════
class _ResultRow {
  String name; // اسم الفحص الفرعي (مثال: TWBCS) أو نص العنوان
  String value; // القيمة (مثال: 10.9) - يدعم نص متعدد السطور
  String unit; // الوحدة الخاصة بهذا السطر (مثال: X10³/µL)
  String normalRange; // المدى الطبيعي الخاص بهذا السطر (مثال: 4.0 - 11.0)
  bool isHeader; // true = سطر عنوان فقط بدون value/unit/normalRange
  bool bold;
  bool italic;
  double fontSize;

  _ResultRow({
    this.name = '',
    this.value = '',
    this.unit = '',
    this.normalRange = '',
    this.isHeader = false,
    this.bold = false,
    this.italic = false,
    this.fontSize = 13,
  });

  Map<String, dynamic> toJson() => {
        'name': name,
        'value': value,
        'unit': unit,
        'normalRange': normalRange,
        'isHeader': isHeader,
        'bold': bold,
        'italic': italic,
        'fontSize': fontSize,
      };

  factory _ResultRow.fromJson(Map<String, dynamic> j) {
    // توافق مع الصيغة القديمة (text فقط) لو موجودة بيانات قديمة محفوظة
    if (j.containsKey('text') && !j.containsKey('name')) {
      return _ResultRow(
        name: j['text'] ?? '',
        value: '',
        unit: '',
        normalRange: '',
        isHeader: true,
        bold: j['bold'] ?? false,
        italic: j['italic'] ?? false,
        fontSize: (j['fontSize'] as num?)?.toDouble() ?? 13,
      );
    }
    return _ResultRow(
      name: j['name'] ?? '',
      value: j['value'] ?? '',
      unit: j['unit'] ?? '',
      normalRange: j['normalRange'] ?? '',
      isHeader: j['isHeader'] ?? false,
      bold: j['bold'] ?? false,
      italic: j['italic'] ?? false,
      fontSize: (j['fontSize'] as num?)?.toDouble() ?? 13,
    );
  }

  // هل السطر له محتوى حقيقي؟
  bool get hasContent =>
      name.trim().isNotEmpty || value.trim().isNotEmpty;
}

// ═══════════════════════════════════════════
// حاوية نتيجة الفحص الكاملة
// تحتوي على إعداد "عرض الوحدة/المدى الطبيعي" + قائمة السطور
// مخزّنة كـ JSON واحد في عمود result (نفس عمود قاعدة البيانات القديم)
// ═══════════════════════════════════════════
class _TestResult {
  bool showUnitNormal; // لو false: ما بنعرض أعمدة الوحدة والمدى الطبيعي أصلاً
  List<_ResultRow> rows;

  _TestResult({this.showUnitNormal = true, List<_ResultRow>? rows})
      : rows = rows ?? [];

  bool get hasContent => rows.any((r) => r.hasContent);

  String encode() => jsonEncode({
        'showUnitNormal': showUnitNormal,
        'rows': rows.map((r) => r.toJson()).toList(),
      });

  static _TestResult decode(String? stored) {
    if (stored == null || stored.trim().isEmpty) return _TestResult();
    try {
      final decoded = jsonDecode(stored);

      // الصيغة الجديدة: object فيه showUnitNormal + rows
      if (decoded is Map) {
        final rowsRaw = decoded['rows'];
        final rows = (rowsRaw is List)
            ? rowsRaw
                .whereType<Map>()
                .map((e) => _ResultRow.fromJson(e as Map<String, dynamic>))
                .toList()
            : <_ResultRow>[];
        return _TestResult(
          showUnitNormal: decoded['showUnitNormal'] ?? true,
          rows: rows,
        );
      }

      // الصيغة القديمة: array مباشر من الصفوف
      if (decoded is List) {
        if (decoded.isNotEmpty && decoded.first is Map) {
          final rows = decoded
              .map((e) => _ResultRow.fromJson(e as Map<String, dynamic>))
              .toList();
          // البيانات القديمة كانت دايماً بتعرض أعمدة الوحدة/المدى الطبيعي
          return _TestResult(showUnitNormal: true, rows: rows);
        }
      }

      // صيغة قديمة جداً: نص خام مباشر
      return _TestResult(
          showUnitNormal: true, rows: [_ResultRow(name: stored, isHeader: true)]);
    } catch (_) {
      return _TestResult(
          showUnitNormal: true, rows: [_ResultRow(name: stored, isHeader: true)]);
    }
  }

  // هل فيه محتوى حقيقي مخزّن في النص الخام (بدون فك تشفير كامل لقائمة الواجهة)؟
  static bool hasStoredContent(String? stored) {
    if (stored == null || stored.trim().isEmpty) return false;
    return decode(stored).hasContent;
  }
}

// ═══════════════════════════════════════════
// الشاشة الرئيسية
// ═══════════════════════════════════════════
class DoctorScreen extends StatefulWidget {
  final Map<String, dynamic> currentUser;
  const DoctorScreen({super.key, required this.currentUser});
  @override
  State<DoctorScreen> createState() => _DoctorScreenState();
}

class _DoctorScreenState extends State<DoctorScreen> {
  List<Map<String, dynamic>> _visits = [];
  List<Map<String, dynamic>> _patients = [];
  Map<int, String> _visitStatus = {};
  bool _loading = true;
  int? _selectedVisitId;
  List<Map<String, dynamic>> _visitTests = [];
  bool _loadingTests = false;

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    setState(() => _loading = true);

    _visits =
        List<Map<String, dynamic>>.from(await ApiService.getVisits());
    _patients =
        List<Map<String, dynamic>>.from(await ApiService.getPatients());

    final allVisitTests = List<Map<String, dynamic>>.from(
        await ApiService.getAllVisitTests());

    _visitStatus.clear();
    final testsByVisit = <int, List<Map<String, dynamic>>>{};

    for (var t in allVisitTests) {
      final vid = t['visit_id'] as int;
      testsByVisit.putIfAbsent(vid, () => []).add(t);
    }

    for (var visit in _visits) {
      final vid = visit['id'] as int;
      final tests = testsByVisit[vid] ?? [];

      if (tests.isEmpty) {
        _visitStatus[vid] = 'new';
      } else {
        final completed = tests
            .where((t) => _TestResult.hasStoredContent(t['result'] as String?))
            .length;

        if (completed == tests.length) {
          _visitStatus[vid] = 'complete';
        } else if (completed == 0) {
          _visitStatus[vid] = 'new';
        } else {
          _visitStatus[vid] = 'partial';
        }
      }
    }

    setState(() => _loading = false);
  }

  Future<void> _selectVisit(int visitId) async {
    setState(() {
      _selectedVisitId = visitId;
      _loadingTests = true;
    });
    _visitTests = List<Map<String, dynamic>>.from(
        await ApiService.getVisitTests(visitId));
    setState(() => _loadingTests = false);
  }

  bool get _allResultsDone =>
      _visitTests.isNotEmpty &&
      _visitTests
          .every((t) => _TestResult.hasStoredContent(t['result'] as String?));

  void _showSnack(String msg, {bool isError = false}) {
    ScaffoldMessenger.of(context).showSnackBar(SnackBar(
      content: Text(msg, style: const TextStyle(fontFamily: 'Cairo')),
      backgroundColor: isError ? _error : const Color(0xFF1B5E20),
      behavior: SnackBarBehavior.floating,
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      margin: const EdgeInsets.all(16),
    ));
  }

  // ─── عرض النتائج في الشاشة ───────────────────────────────
  // لو سطر واحد بس بقيمة وبدون unit/normalRange منفصلين → نص بسيط
  // لو فيه أكتر من سطر، أو فيه عناوين فرعية → جدول
  // عدد الأعمدة في الجدول بيعتمد على showUnitNormal الخاص بالفحص
  Widget _buildResultWidget(String? stored) {
    final tr = _TestResult.decode(stored);
    final visibleRows = tr.rows.where((r) => r.hasContent).toList();
    if (visibleRows.isEmpty) return const SizedBox();

    final valueRows = visibleRows.where((r) => !r.isHeader).toList();
    final showAsTable = visibleRows.length > 1 || valueRows.length > 1;

    if (!showAsTable) {
      // سطر واحد فقط
      final r = visibleRows.first;
      final text = r.isHeader
          ? r.name
          : [r.name, r.value].where((s) => s.trim().isNotEmpty).join(': ');
      return Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Expanded(
            child: Text(
              text,
              style: TextStyle(
                fontFamily: 'Cairo',
                fontSize: r.fontSize,
                fontWeight: r.bold ? FontWeight.w800 : FontWeight.w700,
                fontStyle: r.italic ? FontStyle.italic : FontStyle.normal,
                color: const Color(0xFF2E7D32),
              ),
            ),
          ),
          if (!r.isHeader && tr.showUnitNormal && r.unit.trim().isNotEmpty)
            Padding(
              padding: const EdgeInsets.only(right: 6),
              child: Text(r.unit,
                  style: const TextStyle(
                      fontFamily: 'Cairo',
                      fontSize: 11,
                      color: _textHint,
                      fontWeight: FontWeight.w700)),
            ),
        ],
      );
    }

    // ── عرض جدولي مصغّر داخل الشاشة ──
    // عدد الأعمدة بيتغيّر حسب showUnitNormal: عمودين (الفحص/القيمة) أو 4 أعمدة كاملة
    final columnWidths = tr.showUnitNormal
        ? const <int, TableColumnWidth>{
            0: FlexColumnWidth(2.4),
            1: FlexColumnWidth(1.4),
            2: FlexColumnWidth(1.4),
            3: FlexColumnWidth(2),
          }
        : const <int, TableColumnWidth>{
            0: FlexColumnWidth(2.4),
            1: FlexColumnWidth(2.6),
          };

    return Container(
      decoration: BoxDecoration(
        border: Border.all(color: _divider),
        borderRadius: BorderRadius.circular(8),
      ),
      clipBehavior: Clip.antiAlias,
      child: Table(
        columnWidths: columnWidths,
        children: [
          TableRow(
            decoration: const BoxDecoration(color: Color(0xFFE3F2FD)),
            children: tr.showUnitNormal
                ? const [
                    _MiniHeaderCell('الفحص'),
                    _MiniHeaderCell('القيمة'),
                    _MiniHeaderCell('الوحدة'),
                    _MiniHeaderCell('المدى الطبيعي'),
                  ]
                : const [
                    _MiniHeaderCell('الفحص'),
                    _MiniHeaderCell('القيمة'),
                  ],
          ),
          ...visibleRows.map((r) {
            if (r.isHeader) {
              final headerCell = _MiniCell(
                r.name,
                bold: true,
                italic: r.italic,
                fontSize: r.fontSize,
                span: true,
              );
              return TableRow(
                decoration: const BoxDecoration(color: Color(0xFFF8FBFF)),
                children: tr.showUnitNormal
                    ? [
                        headerCell,
                        const _MiniCell(''),
                        const _MiniCell(''),
                        const _MiniCell(''),
                      ]
                    : [
                        headerCell,
                        const _MiniCell(''),
                      ],
              );
            }
            final nameCell = _MiniCell(r.name,
                bold: r.bold, italic: r.italic, fontSize: r.fontSize);
            final valueCell = _MiniCell(r.value,
                bold: true,
                italic: r.italic,
                fontSize: r.fontSize,
                color: const Color(0xFF2E7D32));
            return TableRow(
              children: tr.showUnitNormal
                  ? [
                      nameCell,
                      valueCell,
                      _MiniCell(r.unit.isNotEmpty ? r.unit : '-'),
                      _MiniCell(r.normalRange.isNotEmpty ? r.normalRange : '-'),
                    ]
                  : [
                      nameCell,
                      valueCell,
                    ],
            );
          }),
        ],
      ),
    );
  }

  // ─── تحويل النتائج الفرعية إلى صفوف HTML للطباعة ─────────
  // كل فحص بيظهر باسمه كعنوان، وتحته جدول لكل سطر فرعي
  // عدد الأعمدة المطبوعة بيعتمد على showUnitNormal الخاص بالفحص
  String _testToPrintHtml(Map<String, dynamic> t) {
    final tr = _TestResult.decode(t['result'] as String?);
    final rows = tr.rows.where((r) => r.hasContent).toList();
    final testName = t['test_name'] ?? '';
    final colspan = tr.showUnitNormal ? 4 : 2;

    if (rows.isEmpty) return '';

    final buf = StringBuffer();

    // عنوان الفحص نفسه (دايماً يظهر فوق)
    buf.writeln(
        '<tr class="test-title-row"><td colspan="$colspan">$testName</td></tr>');

    final valueRows = rows.where((r) => !r.isHeader).toList();
    final hasMultiple = rows.length > 1 || valueRows.length > 1;

    String _withLineBreaks(String s) => s.replaceAll('\n', '<br>');

    if (!hasMultiple) {
      // فحص بنتيجة واحدة بسيطة
      final r = rows.first;
      String text = _withLineBreaks(r.isHeader ? r.name : r.value);
      if (r.bold) text = '<b>$text</b>';
      if (r.italic) text = '<i>$text</i>';
      if (tr.showUnitNormal) {
        final unit = (!r.isHeader && r.unit.isNotEmpty) ? r.unit : '-';
        final range =
            (!r.isHeader && r.normalRange.isNotEmpty) ? r.normalRange : '-';
        buf.writeln('''
        <tr>
          <td class="sub-name">${r.isHeader ? '' : _withLineBreaks(r.name)}</td>
          <td class="result-cell">$text</td>
          <td class="center">$unit</td>
          <td class="center">$range</td>
        </tr>
      ''');
      } else {
        buf.writeln('''
        <tr>
          <td class="sub-name">${r.isHeader ? '' : _withLineBreaks(r.name)}</td>
          <td class="result-cell">$text</td>
        </tr>
      ''');
      }
      return buf.toString();
    }

    // فحص بنتائج فرعية متعددة (زي CBC أو Urine Analysis)
    for (final r in rows) {
      if (r.isHeader) {
        String label = _withLineBreaks(r.name);
        if (r.bold) label = '<b>$label</b>';
        if (r.italic) label = '<i>$label</i>';
        buf.writeln(
            '<tr class="sub-header-row"><td colspan="$colspan">$label</td></tr>');
        continue;
      }
      String valueText = _withLineBreaks(r.value);
      if (r.bold) valueText = '<b>$valueText</b>';
      if (r.italic) valueText = '<i>$valueText</i>';
      if (tr.showUnitNormal) {
        buf.writeln('''
        <tr>
          <td class="sub-name">${_withLineBreaks(r.name)}</td>
          <td class="result-cell">$valueText</td>
          <td class="center">${r.unit.isNotEmpty ? r.unit : '-'}</td>
          <td class="center">${r.normalRange.isNotEmpty ? r.normalRange : '-'}</td>
        </tr>
      ''');
      } else {
        buf.writeln('''
        <tr>
          <td class="sub-name">${_withLineBreaks(r.name)}</td>
          <td class="result-cell">$valueText</td>
        </tr>
      ''');
      }
    }
    return buf.toString();
  }

  // ─── Print ────────────────────────────────────────────────
  void _printResults() {
    final visit =
        _visits.where((v) => v['id'] == _selectedVisitId).firstOrNull;
    if (visit == null) return;

    final patientName = visit['patient_name'] ?? '';
    final dt = DateTime.tryParse(visit['date'] ?? '') ?? DateTime.now();
    final dateStr =
        '${dt.day.toString().padLeft(2, '0')}/${dt.month.toString().padLeft(2, '0')}/${dt.year}';

    final now = DateTime.now();
    final printTime =
        '${now.hour.toString().padLeft(2, '0')}:${now.minute.toString().padLeft(2, '0')}';

    final StringBuffer rowsBuffer = StringBuffer();
    // كل فحص بييجي بجدول مستقل عشان نقدر نتحكم في عدد الأعمدة لكل فحص على حدة
    for (var t in _visitTests) {
      final tr = _TestResult.decode(t['result'] as String?);
      if (!tr.hasContent) continue;
      final headerCells = tr.showUnitNormal
          ? '''
            <th>Test</th>
            <th>Value</th>
            <th class="center">Unit</th>
            <th class="center">Normal Range</th>
          '''
          : '''
            <th>Test</th>
            <th>Value</th>
          ''';
      rowsBuffer.writeln('''
        <table>
          <thead><tr>$headerCells</tr></thead>
          <tbody>
            ${_testToPrintHtml(t)}
          </tbody>
        </table>
      ''');
    }

    final htmlContent = '''
