      direction: ltr;
      line-height: 1.5;
    }

    .header { text-align:center; margin-bottom: 6px; }
    .header img { max-width: 100%; height: auto; max-height: 110px; object-fit: contain; }
    .sub-line { text-align:center; font-size:13px; color:#546E7A; margin-top:2px; margin-bottom:10px; font-weight:700; }

    hr.thick { border:none; border-top:3px solid #8B0000; margin:12px 0; }
    hr.thin  { border:none; border-top:1px solid #ddd; margin:10px 0; }

    .info-row {
      display: flex; gap: 10px; margin-bottom: 8px; align-items: stretch;
    }
    .info-field {
      display: flex; align-items: center; border: 1.5px solid #90CAF9;
      border-radius: 6px; overflow: hidden; font-size: 13.5px; font-weight: 700;
