''';

    final blob = html.Blob([htmlContent], 'text/html');
    final url = html.Url.createObjectUrlFromBlob(blob);
    html.window.open(url, '_blank');
    html.Url.revokeObjectUrl(url);
  }

  String _paymentLabel(String method) {
    switch (method) {
      case 'cash':
        return 'كاش';
      case 'bank':
        return 'بنك';
      case 'fwry':
        return 'فوري';
      case 'okash':
        return 'اوكاش';
      case 'mycash':
        return 'ماي كاشي';
      default:
        return method;
    }
  }

  // ─── زر التنسيق المساعد ───────────────────────────────────
  Widget _fmtBtn(
    String label,
    bool active,
    VoidCallback onTap, {
    bool bold = false,
    bool italic = false,
  }) {
    return GestureDetector(
      onTap: onTap,
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 9, vertical: 3),
        decoration: BoxDecoration(
          color: active ? _primary : Colors.white,
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: active ? _primary : _divider),
        ),
        child: Text(
          label,
          style: TextStyle(
            fontSize: 13,
            color: active ? Colors.white : _textSecondary,
            fontWeight: bold ? FontWeight.w900 : FontWeight.normal,
            fontStyle: italic ? FontStyle.italic : FontStyle.normal,
            fontFamily: 'Cairo',
          ),
        ),
      ),
    );
  }

  // ─── حقل حر لاختيار حجم الخط (بدل الأزرار الثابتة) ────────
  // بيسمح بإدخال أي رقم بحرية + أزرار +/- سريعة
  Widget _fontSizeField(double value, ValueChanged<double> onChanged) {
    final ctrl = TextEditingController(text: value.toStringAsFixed(0));
    ctrl.selection = TextSelection.collapsed(offset: ctrl.text.length);
    return Row(mainAxisSize: MainAxisSize.min, children: [
      const Text('حجم الخط:',
          style: TextStyle(
              fontSize: 11, color: _textHint, fontFamily: 'Cairo')),
      const SizedBox(width: 6),
      InkWell(
        onTap: () => onChanged((value - 1).clamp(6, 72)),
        borderRadius: BorderRadius.circular(6),
        child: Container(
          padding: const EdgeInsets.all(4),
          decoration: BoxDecoration(
              border: Border.all(color: _divider),
              borderRadius: BorderRadius.circular(6)),
          child: const Icon(Icons.remove, size: 14, color: _textSecondary),
        ),
      ),
      const SizedBox(width: 4),
      SizedBox(
        width: 38,
        height: 28,
        child: TextField(
          controller: ctrl,
          textAlign: TextAlign.center,
          keyboardType: TextInputType.number,
          style: const TextStyle(fontSize: 12, fontFamily: 'Cairo'),
          decoration: InputDecoration(
            isDense: true,
            contentPadding: const EdgeInsets.symmetric(vertical: 4),
            border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(6),
                borderSide: const BorderSide(color: _divider)),
            enabledBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(6),
                borderSide: const BorderSide(color: _divider)),
          ),
          onChanged: (v) {
            final parsed = double.tryParse(v);
            if (parsed != null && parsed >= 6 && parsed <= 72) {
              onChanged(parsed);
            }
          },
        ),
      ),
      const SizedBox(width: 4),
      InkWell(
        onTap: () => onChanged((value + 1).clamp(6, 72)),
        borderRadius: BorderRadius.circular(6),
        child: Container(
          padding: const EdgeInsets.all(4),
          decoration: BoxDecoration(
              border: Border.all(color: _divider),
              borderRadius: BorderRadius.circular(6)),
          child: const Icon(Icons.add, size: 14, color: _textSecondary),
        ),
      ),
    ]);
  }

  // مساعدة لإنشاء Decoration للحقول مع دعم وضع القفل
  InputDecoration deco(String hint, {bool locked = false}) {
    return InputDecoration(
      hintText: hint,
      hintStyle: const TextStyle(fontFamily: 'Cairo', color: _textHint, fontSize: 12),
      filled: true,
      fillColor: Colors.white,
      isDense: true,
      contentPadding: const EdgeInsets.symmetric(horizontal: 10, vertical: 10),
      border: OutlineInputBorder(borderRadius: BorderRadius.circular(8), borderSide: const BorderSide(color: _divider)),
      enabledBorder: OutlineInputBorder(borderRadius: BorderRadius.circular(8), borderSide: const BorderSide(color: _divider)),
      focusedBorder: OutlineInputBorder(borderRadius: BorderRadius.circular(8), borderSide: const BorderSide(color: _primary, width: 2)),
      suffixIcon: locked ? const Icon(Icons.lock_outline, size: 18, color: _textHint) : null,
    );
  }

// ─── إعادة بناء الصفوف من القالب مع الحفاظ على القيم المدخلة ───
  // بتستخدم لو حابب "تحديث من القالب" بعد ما عدّلت الفحوصات الفرعية
  // في شاشة إدارة الفحوصات، عشان تجيب أي فحص فرعي جديد اتضاف
  List<_ResultRow> _syncRowsWithTemplate(
      List<_ResultRow> currentRows, List<SubTest> subTests) {
    final byName = <String, _ResultRow>{};
    for (final r in currentRows) {
      if (!r.isHeader) byName[r.name.trim()] = r;
    }
    return subTests.map((s) {
      final existing = byName[s.name.trim()];
      return _ResultRow(
        name: s.name,
        unit: s.unit,
        normalRange: s.normalRange,
        value: existing?.value ?? '',
        bold: existing?.bold ?? false,
        italic: existing?.italic ?? false,
        fontSize: existing?.fontSize ?? 13,
      );
    }).toList();
  }
// جلب الفحوصات الفرعية من جدول الفحوصات
Future<List<SubTest>> _getSubTests(int testId) async {
  try {
    final allTests = await ApiService.getTests();
    final test = allTests.firstWhere((t) => t['id'] == testId, orElse: () => <String, dynamic>{});
    return SubTest.listFromTest(test);
  } catch (e) {
    return [];
  }
}
  // ─── Dialog إدخال النتيجة الغنية ─────────────────────────
  void _showResultDialog(Map<String, dynamic> vt) async {
    final testId = vt['test_id'] as int?;
    final testName = vt['test_name'] ?? 'فحص';

    // جلب الفحوصات الفرعية (القالب) من جدول الفحوصات الأصلي
    List<SubTest> subTests = [];
    if (testId != null) {
      subTests = await _getSubTests(testId);
    }
    final hasTemplate = subTests.isNotEmpty;

    // تحميل النتيجة السابقة
    final existingResult = vt['result'] as String?;
    final tr = existingResult != null && existingResult.isNotEmpty
        ? _TestResult.decode(existingResult)
        : _TestResult(showUnitNormal: true, rows: []);

    List<_ResultRow> rows = List.from(tr.rows);
    bool showUnitNormal = tr.showUnitNormal;

    // إذا أول مرة وفيه قالب → نبني الصفوف تلقائياً
    if (rows.isEmpty && hasTemplate) {
      rows = subTests.map((s) => _ResultRow(
            name: s.name,
            unit: s.unit,
            normalRange: s.normalRange,
            value: '',
            isHeader: false,
          )).toList();
      showUnitNormal = true;
    } else if (rows.isEmpty) {
      rows.add(_ResultRow());
    }

    showDialog(
      context: context,
      barrierColor: Colors.black54,
      builder: (ctx) {
        return StatefulBuilder(builder: (ctx, setDlg) {
          return Directionality(
            textDirection: TextDirection.rtl,
            child: Dialog(
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),
              clipBehavior: Clip.antiAlias,
              child: SizedBox(
                width: hasTemplate ? 920 : 780,
                child: Column(mainAxisSize: MainAxisSize.min, children: [
                  // Header
                  Container(
                    padding: const EdgeInsets.fromLTRB(24, 20, 24, 20),
                    decoration: const BoxDecoration(
                        gradient: LinearGradient(colors: [_primary, _primaryDark])),
                    child: Row(children: [
                      Container(
                        width: 40,
                        height: 40,
                        decoration: BoxDecoration(
                            color: Colors.white24,
                            borderRadius: BorderRadius.circular(10)),
                        child: const Icon(Icons.edit_note_rounded,
                            color: Colors.white, size: 22),
                      ),
                      const SizedBox(width: 12),
                      Expanded(
                        child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(testName,
                                  style: const TextStyle(
                                      color: Colors.white,
                                      fontSize: 16,
                                      fontWeight: FontWeight.w800,
                                      fontFamily: 'Cairo')),
                              Text(
                                hasTemplate
                                    ? 'فحص فرعي - أدخل القيم فقط'
                                    : 'أدخل نتيجة الفحص',
                                style: const TextStyle(
                                    color: Colors.white70,
                                    fontSize: 12,
                                    fontFamily: 'Cairo'),
                              ),
                            ]),
                      ),
                      IconButton(
                          icon: const Icon(Icons.close, color: Colors.white70),
                          onPressed: () => Navigator.pop(ctx)),
                    ]),
                  ),

                  // شريط الإعدادات
                  Container(
                    width: double.infinity,
                    padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 10),
                    color: const Color(0xFFFFF8E1),
                    child: Row(children: [
                      const Icon(Icons.view_column_rounded, size: 18, color: Color(0xFFF59E0B)),
                      const SizedBox(width: 8),
                      Switch(
                        value: showUnitNormal,
                        activeColor: _primary,
                        onChanged: (v) => setDlg(() => showUnitNormal = v),
                      ),
                      Text(
                        showUnitNormal ? 'مفعّل (جدول كامل)' : 'معطّل (اسم + قيمة فقط)',
