                                              Icons.new_releases_rounded;
                                          statusText = 'جديد';
                                      }

                                      return GestureDetector(
                                        onTap: () => _selectVisit(vid),
                                        child: AnimatedContainer(
                                          duration: const Duration(
                                              milliseconds: 150),
                                          padding: const EdgeInsets.all(12),
                                          decoration: BoxDecoration(
                                            color: isSelected
                                                ? const Color(0xFFE3F2FD)
                                                : _bg,
                                            borderRadius:
                                                BorderRadius.circular(10),
                                            border: Border.all(
                                              color: isSelected
                                                  ? _primary
                                                  : _divider,
                                              width: isSelected ? 2 : 1,
                                            ),
                                          ),
                                          child: Row(children: [
                                            CircleAvatar(
                                              radius: 18,
                                              backgroundColor: isSelected
                                                  ? _primary
                                                  : statusColor
                                                      .withOpacity(0.15),
                                              child: Icon(statusIcon,
                                                  color: isSelected
                                                      ? Colors.white
                                                      : statusColor,
                                                  size: 20),
                                            ),
                                            const SizedBox(width: 10),
                                            Expanded(
                                              child: Column(
                                                crossAxisAlignment:
                                                    CrossAxisAlignment.start,
                                                children: [
                                                  Text(
                                                    v['patient_name'] ?? '',
                                                    style: const TextStyle(
                                                        fontWeight:
                                                            FontWeight.w700,
                                                        fontFamily: 'Cairo',
                                                        color: _textPrimary,
                                                        fontSize: 13),
                                                  ),
                                                  Text(
                                                    '${dt.day}/${dt.month}/${dt.year} • $statusText',
                                                    style: TextStyle(
                                                        fontSize: 11,
                                                        color: isSelected
                                                            ? _primary
                                                            : _textHint,
                                                        fontFamily: 'Cairo'),
                                                  ),
                                                ],
                                              ),
                                            ),
                                            Text(
                                              '${(v['total'] as num).toStringAsFixed(0)} ج',
                                              style: const TextStyle(
                                                  fontFamily: 'Cairo',
                                                  fontWeight: FontWeight.w700,
                                                  color: _primary,
                                                  fontSize: 12),
                                            ),
                                          ]),
                                        ),
                                      );
                                    },
                                  ),
                          ),
                        ]),
                      ),
                    ),

                    // ── الفحوصات ──
                    Expanded(
                      child: _selectedVisitId == null
                          ? Center(
                              child: Column(
                              mainAxisAlignment: MainAxisAlignment.center,
                              children: [
                                Container(
                                    width: 80,
                                    height: 80,
                                    decoration: BoxDecoration(
                                        color: _bg, shape: BoxShape.circle),
                                    child: const Icon(
                                        Icons.touch_app_rounded,
                                        size: 40,
                                        color: _textHint)),
                                const SizedBox(height: 16),
                                const Text('اختر زيارة لعرض فحوصاتها',
                                    style: TextStyle(
                                        fontFamily: 'Cairo',
                                        color: _textSecondary,
                                        fontSize: 15,
                                        fontWeight: FontWeight.w700)),
                              ],
                            ))
                          : Container(
                              margin:
                                  const EdgeInsets.fromLTRB(0, 24, 24, 24),
                              decoration: BoxDecoration(
                                  color: _surface,
                                  borderRadius: BorderRadius.circular(16),
                                  boxShadow: const [
                                    BoxShadow(
                                        color: Color(0x0A000000),
                                        blurRadius: 10,
                                        offset: Offset(0, 2))
                                  ]),
                              clipBehavior: Clip.antiAlias,
                              child: Column(children: [
                                // ── Tests Header ──
                                Container(
                                  padding: const EdgeInsets.symmetric(
                                      horizontal: 16, vertical: 14),
                                  decoration: const BoxDecoration(
                                      gradient: LinearGradient(colors: [
                                        Color(0xFFF0F7FF),
                                        Color(0xFFE8F4FD)
                                      ]),
                                      border: Border(
                                          bottom: BorderSide(
                                              color: _divider))),
                                  child: Row(children: [
                                    const Icon(Icons.science_rounded,
                                        color: _primary, size: 20),
                                    const SizedBox(width: 8),
                                    Expanded(
                                      child: Text(
                                          'فحوصات ${_visits.where((v) => v['id'] == _selectedVisitId).firstOrNull?['patient_name'] ?? ''}',
                                          style: const TextStyle(
                                              fontWeight: FontWeight.w800,
                                              fontFamily: 'Cairo',
                                              color: _textPrimary)),
                                    ),
                                    if (_allResultsDone)
                                      ElevatedButton.icon(
                                        onPressed: _printResults,
                                        icon: const Icon(
                                            Icons.print_rounded,
                                            size: 18),
                                        label: const Text('طباعة النتائج',
                                            style: TextStyle(
                                                fontFamily: 'Cairo',
                                                fontWeight:
                                                    FontWeight.w700)),
                                        style: ElevatedButton.styleFrom(
                                          backgroundColor:
                                              const Color(0xFF2E7D32),
                                          foregroundColor: Colors.white,
                                          elevation: 0,
                                          shape: RoundedRectangleBorder(
                                              borderRadius:
                                                  BorderRadius.circular(10)),
                                          padding:
                                              const EdgeInsets.symmetric(
                                                  horizontal: 18,
                                                  vertical: 10),
                                        ),
                                      ),
                                  ]),
                                ),

                                // ── Tests List ──
                                Expanded(
                                  child: _loadingTests
                                      ? const Center(
                                          child: CircularProgressIndicator(
                                              color: _primary))
                                      : _visitTests.isEmpty
                                          ? const Center(
                                              child: Text('لا توجد فحوصات',
                                                  style: TextStyle(
                                                      fontFamily: 'Cairo',
                                                      color: _textHint)))
                                          : ListView.separated(
                                              padding:
                                                  const EdgeInsets.all(16),
                                              itemCount:
                                                  _visitTests.length,
                                              separatorBuilder: (_, __) =>
                                                  const Divider(
                                                      color: _divider),
                                              itemBuilder: (_, i) {
                                                final t = _visitTests[i];
                                                final hasResult =
                                                    _TestResult
                                                        .hasStoredContent(
                                                            t['result']
                                                                as String?);

                                                return Padding(
                                                  padding: const EdgeInsets
                                                      .symmetric(
                                                      vertical: 8),
                                                  child: Row(
                                                    crossAxisAlignment:
                                                        CrossAxisAlignment
                                                            .start,
                                                    children: [
                                                      // ── أيقونة الحالة ──
                                                      Container(
                                                        width: 42,
                                                        height: 42,
                                                        margin:
                                                            const EdgeInsets
                                                                .only(top: 2),
                                                        decoration: BoxDecoration(
                                                            color: hasResult
                                                                ? const Color(
                                                                    0xFFE8F5E9)
                                                                : const Color(
                                                                    0xFFFFF8E1),
                                                            borderRadius:
                                                                BorderRadius
                                                                    .circular(
                                                                        10)),
                                                        child: Icon(
                                                            hasResult
                                                                ? Icons
                                                                    .check_circle_rounded
                                                                : Icons
                                                                    .pending_rounded,
                                                            color: hasResult
                                                                ? const Color(
                                                                    0xFF2E7D32)
                                                                : const Color(
                                                                    0xFFF59E0B),
                                                            size: 22),
                                                      ),
                                                      const SizedBox(
                                                          width: 14),

                                                      // ── معلومات الفحص والنتيجة ──
                                                      Expanded(
                                                        child: Column(
                                                          crossAxisAlignment:
                                                              CrossAxisAlignment
                                                                  .start,
                                                          children: [
                                                            // اسم الفحص (يظهر فوق دائماً)
                                                            Text(
                                                                t['test_name'] ??
                                                                    '',
                                                                style: const TextStyle(
                                                                    fontWeight:
                                                                        FontWeight
                                                                            .w800,
                                                                    fontFamily:
                                                                        'Cairo',
                                                                    fontSize:
                                                                        14,
                                                                    color:
                                                                        _primaryDark)),

                                                            // ══ النتيجة (نص بسيط أو جدول، بعدد أعمدة متغيّر) ══
                                                            if (hasResult) ...[
                                                              const SizedBox(
                                                                  height: 6),
                                                              _buildResultWidget(
                                                                  t['result']
                                                                      as String?),
                                                            ] else
                                                              const Padding(
                                                                padding:
                                                                    EdgeInsets
                                                                        .only(
                                                                            top:
                                                                                2),
                                                                child: Text(
                                                                    'لم تُدخل النتيجة بعد',
                                                                    style: TextStyle(
                                                                        fontSize:
                                                                            11,
                                                                        color:
                                                                            _textHint,
                                                                        fontFamily:
                                                                            'Cairo')),
                                                              ),
                                                          ],
                                                        ),
                                                      ),

                                                      // ── زر إدخال/تعديل ──
                                                      const SizedBox(
                                                          width: 12),
                                                      ElevatedButton.icon(
                                                        onPressed: () =>
                                                            _showResultDialog(
                                                                t),
                                                        icon: Icon(
                                                            hasResult
                                                                ? Icons
                                                                    .edit_rounded
                                                                : Icons
                                                                    .add_rounded,
                                                            size: 16),
                                                        label: Text(
                                                            hasResult
                                                                ? 'تعديل'
                                                                : 'إدخال',
                                                            style: const TextStyle(
                                                                fontFamily:
                                                                    'Cairo',
                                                                fontWeight:
                                                                    FontWeight
                                                                        .w700,
                                                                fontSize:
                                                                    12)),
                                                        style: ElevatedButton
                                                            .styleFrom(
                                                          backgroundColor:
                                                              hasResult
                                                                  ? const Color(
                                                                      0xFFE3F2FD)
                                                                  : _primary,
                                                          foregroundColor:
                                                              hasResult
                                                                  ? _primary
                                                                  : Colors
                                                                      .white,
                                                          elevation: 0,
                                                          shape: RoundedRectangleBorder(
                                                              borderRadius:
                                                                  BorderRadius
                                                                      .circular(
                                                                          8)),
                                                          padding: const EdgeInsets
                                                              .symmetric(
                                                              horizontal: 14,
                                                              vertical: 8),
                                                        ),
                                                      ),
                                                    ],
                                                  ),
                                                );
                                              },
                                            ),
                                ),
                              ]),
                            ),
                    ),
                  ],
                ),
        ),
      ]),
    );
  }
}

