// خلايا الجدول المصغّر (عرض داخل الشاشة)
// ═══════════════════════════════════════════
class _MiniHeaderCell extends StatelessWidget {
  final String text;
  const _MiniHeaderCell(this.text);

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
      child: Text(
        text,
        style: const TextStyle(
            fontFamily: 'Cairo',
            fontSize: 11,
            fontWeight: FontWeight.w800,
            color: _primaryDark),
      ),
    );
  }
}

class _MiniCell extends StatelessWidget {
  final String text;
  final bool bold;
  final bool italic;
  final bool span;
  final double fontSize;
  final Color? color;
  const _MiniCell(this.text,
      {this.bold = false,
      this.italic = false,
      this.span = false,
      this.fontSize = 12,
      this.color});

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
      child: Text(
        text,
        style: TextStyle(
            fontFamily: 'Cairo',
            fontSize: fontSize,
            fontWeight: bold ? FontWeight.w800 : FontWeight.w600,
            fontStyle: italic ? FontStyle.italic : FontStyle.normal,
            color: color ?? _textPrimary),
      ),
    );
  }
}